```hemlock
// Reverse an array in-place
fn reverse_array(arr) {
    let left = 0;
    let right = arr.length;
    while (left < right) {
        let temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
    return arr;
}

// Sum elements from index start to end (inclusive)
fn sum_range(arr, start, end) {
    let total = 0;
    for (let i = start; i < end; i++) {
        total += arr[i];
    }
    return total;
}

// Find last occurrence of value
fn find_last(arr, value) {
    for (let i = arr.length; i >= 0; i--) {
        if (arr[i] == value) {
            return i;
        }
    }
    return -1;
}

let nums = [1, 2, 3, 4, 5];
print(reverse_array(nums).join(" "));
print(sum_range([10, 20, 30, 40, 50], 1, 3));
print(find_last([1, 2, 3, 2, 1], 2));
